targets.expr:
max by (scaletargetref_name) (
  kube_horizontalpodautoscaler_spec_min_replicas{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"}
  * on (cluster, namespace, horizontalpodautoscaler) group_left (scaletargetref_name)
  group by (cluster, namespace, horizontalpodautoscaler, scaletargetref_name) (kube_horizontalpodautoscaler_info{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"})
)

max by (scaletargetref_name) (
  kube_horizontalpodautoscaler_status_current_replicas{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"}
  * on (cluster, namespace, horizontalpodautoscaler) group_left (scaletargetref_name)
  group by (cluster, namespace, horizontalpodautoscaler, scaletargetref_name) (kube_horizontalpodautoscaler_info{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"})
)

max by (scaletargetref_name) (
  kube_horizontalpodautoscaler_status_desired_replicas{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"}
  * on (cluster, namespace, horizontalpodautoscaler) group_left (scaletargetref_name)
  group by (cluster, namespace, horizontalpodautoscaler, scaletargetref_name) (kube_horizontalpodautoscaler_info{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"})
)

max by (scaletargetref_name) (
  kube_horizontalpodautoscaler_spec_max_replicas{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"}
  * on (cluster, namespace, horizontalpodautoscaler) group_left (scaletargetref_name)
  group by (cluster, namespace, horizontalpodautoscaler, scaletargetref_name) (kube_horizontalpodautoscaler_info{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"})
)

sum by (scaledObject) (
  max by (cluster, namespace, scaledObject, metric, scaler) (
    label_replace(keda_scaler_metrics_value{cluster=~"$cluster", exported_namespace=~"$namespace", scaledObject=~"live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs", scaler=~".*cpu.*|prometheusScaler"}, "namespace", "$1", "exported_namespace", "(.*)")
  )
  / on(cluster, namespace, scaledObject, metric) group_left
  max by (cluster, namespace, scaledObject, metric) (
    label_replace(label_replace(kube_horizontalpodautoscaler_spec_target_metric{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"}, "metric", "$1", "metric_name", "(.+)"), "scaledObject", "$1", "horizontalpodautoscaler", "keda-hpa-(.*)")
  )
)

sum by (scaledObject) (
  max by (cluster, namespace, scaledObject, metric, scaler) (
    label_replace(keda_scaler_metrics_value{cluster=~"$cluster", exported_namespace=~"$namespace", scaledObject=~"live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs", scaler=~".*memory.*"}, "namespace", "$1", "exported_namespace", "(.*)")
  )
  / on(cluster, namespace, scaledObject, metric) group_left
  max by (cluster, namespace, scaledObject, metric) (
    label_replace(label_replace(kube_horizontalpodautoscaler_spec_target_metric{cluster=~"$cluster", namespace=~"$namespace", horizontalpodautoscaler=~"keda-hpa-(live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs)"}, "metric", "$1", "metric_name", "(.+)"), "scaledObject", "$1", "horizontalpodautoscaler", "keda-hpa-(.*)")
  )
)

sum by (scaledObject, scaler) (
  label_replace(rate(keda_scaler_errors{cluster=~"$cluster", exported_namespace=~"$namespace", scaledObject=~"live-store|warpstream-agent-read|warpstream-agent-write|warpstream-agent-jobs"}[$__rate_interval]), "namespace", "$1", "exported_namespace", "(.+)")
)
